sql:
SELECT country, COUNT(*) AS total_vtubers
FROM vtubers
GROUP BY country;

SELECT COUNT(*) 
FROM vtubers 
WHERE country = 'Japan';

SELECT SUM(view_count) AS total_views
  FROM video_performance
  WHERE platform_id = 'twitch';

SELECT vtuber_name, bio
FROM vtubers
WHERE country = 'USA';

SELECT yt.subscriber_count, yt.engagement_score, yt.recent_highest_viewed_video_url
FROM youtube_metrics yt
ORDER BY yt.engagement_score DESC;

SELECT COUNT(DISTINCT vtuber_id) AS num_vtubers
FROM youtube_metrics
WHERE subscriber_count > 100000;
